mapper.select:
SELECT DISTINCT CASE IFNULL(F.FID,'X') != 'X' WHEN 0 THEN 1 ELSE 0 END AS CHK, CASE IFNULL(F.FID,'X') != 'X' WHEN 0 THEN 1 ELSE 0 END AS CHK_C, F.HASH_ID AS ID, F.AP_NO, F.TARGET_ID, F.FID AS INFO_ID, DPCG.data_processing_charge_id AS CHARGE_ID, DPG.processing_flag, (SELECT processing_flag_name FROM pi_data_processing_flag WHERE processing_flag = DPG.processing_flag) AS FLAG, DPCG.data_processing_charge_name AS PATH, DPCG.USER_NO, PU.USER_NAME, DPCG.OK_USER_NO, (SELECT Z.USER_NAME FROM PI_USER Z WHERE Z.USER_NO = DPCG.ok_user_no) AS OK_USER_NAME, DPCG.ADMIN_USER_NO, (SELECT Z.USER_NAME FROM PI_USER Z WHERE Z.USER_NO = DPCG.ADMIN_USER_NO) AS ADMIN_USER_NAME, DATE_FORMAT(DPCG.REGDATE, '%Y-%m-%d %H:%i:%s') AS REGDATE, DATE_FORMAT(DPCG.OKDATE, '%Y-%m-%d %H:%i:%s') AS OKDATE, DPCG.APPROVAL_STATUS, DP.AP_NO AS AP_NO, F.PATH AS FILE_PATH FROM PI_FIND F, PI_DATA_PROCESSING_CHARGE_GROUP AS DPCG LEFT OUTER JOIN PI_USER AS PU ON PU.USER_NO = DPCG.USER_NO LEFT OUTER JOIN pi_data_processing_group AS DPG ON DPCG.data_processing_charge_id = DPG.data_processing_charge_id LEFT OUTER JOIN pi_data_processing AS DP ON DPG.idx = DP.data_processing_group_idx WHERE 1=1 AND DP.target_id = F.target_id AND DP.group_id = F.group_id AND DP.hash_id = F.hash_id AND DPG.idx = DP.data_processing_group_idx AND DPG.target_id = DP.target_id
AND DPG.processing_flag = #{selectList}
AND PATH LIKE concat('%', #{schPath}, '%')
AND DPCG.data_processing_charge_id = #{idx}
AND (DPCG.USER_NO = #{user_no} OR DPCG.OK_USER_NO = #{user_no} OR DPCG.ADMIN_USER_NO= #{user_no}) ORDER BY FLAG DESC

        SELECT data_processing_group_idx FROM pi_data_processing
		WHERE target_id = #{target_id}
		AND hash_id = #{hash_id}
		ORDER BY regdate DESC 
		LIMIT 1

mapper.delete:
        DELETE FROM pi_data_processing
		WHERE target_id = #{target_id}
		AND hash_id = #{hash_id}
		AND data_processing_group_idx = #{key}

        DELETE FROM pi_data_processing_group
		WHERE target_id = #{target_id}
		AND idx = #{key}

mapper.select:
SELECT F.HASH_ID,
	F.TARGET_ID,
	F.AP_NO,
	L.LOCATION_ID,
	F.PATH
FROM pi_locations L ,pi_find F
	JOIN pi_targets T ON T.TARGET_ID = F.TARGET_ID AND T.AP_NO = F.AP_NO 
	WHERE 1 = 1 
		AND F.HASH_ID = #{hash_id}
		AND L.AP_NO = #{ap_no}
		AND L.TARGET_ID = #{target_id}
limit 1;

update.if:
UPDATE PI_FIND F SET REMEDIATION_STATUS = 'False Match' 
	WHERE F.HASH_ID = #{ID}
		AND F.TARGET_ID = #{TARGET_ID}
		AND F.AP_NO = #{AP_NO}

UPDATE PI_SUBPATH S SET REMEDIATION_STATUS = 'False Match' 
	WHERE S.NODE_ID = #{ID}
		AND S.TARGET_ID = #{TARGET_ID}
		AND S.AP_NO = #{AP_NO}
